parameters.sendTo:
={{ $('Get row(s) in sheet').item.json["Contact Email"] }}{{
  (() => {
    const val = $('Get row(s) in sheet').item.json.Guests;
    if (!val || val.length === 0) return '';
    const list = Array.isArray(val) ? val.join(', ') : val;
    return ', ' + list;
  })()
}}

parameters.to:
={{
(() => {
  const raw = String($('Get row(s) in sheet').item.json['Contact Phone'] || '');

  // Remove everything except digits and +
  let phone = raw.replace(/[^0-9+]/g, '');

  // Convert leading 00 to +
  if (phone.startsWith('00')) {
    phone = '+' + phone.slice(2);
  }

  // Add + if missing
  if (!phone.startsWith('+') && phone.length > 0) {
    phone = '+' + phone;
  }

  return phone;
})()
}}

